import scala.collection.mutable.Map
import scala.math._

def solve(nums: Array[Long], k: Long): Long = {
  val totalSum = nums.sum
  var prefixSum = 0L
  var dp = 0L
  val remainderMap = Map[Long, Long]()
  remainderMap(0) = 0L

  for (num <- nums) {
    prefixSum += num
    val currentRemainder = prefixSum % k
    val possibleValue = remainderMap.get(currentRemainder).getOrElse(-Long.MaxValue) + prefixSum
    val newDp = max(dp, possibleValue)
    val newValue = newDp - prefixSum
    if (remainderMap.contains(currentRemainder)) {
      if (newValue > remainderMap(currentRemainder)) {
        remainderMap(currentRemainder) = newValue
      }
    } else {
      remainderMap(currentRemainder) = newValue
    }
    dp = newDp
  }
  totalSum - dp
}
